module voltage_regulator (
    input [4:0] reverse_input,
    output reg [2:0] output_voltage
);

always @(*) begin
    if (reverse_input <= 5'b00010) 
        output_voltage = 3'b000; // Output 0V
    else if (reverse_input > 5'b00010 && (reverse_input - 5'b00010) >= 0) 
        output_voltage = reverse_input - 5'b00010; // Output reverse_input - 2
    else
        output_voltage = 3'b000; // Ensure output is not negative
end

endmodule
